import Foundation

struct UnionFind {
    private var parent: [Int]
    private var size: [Int]
    private(set) var count: Int

    init(_ n: Int) {
        parent = Array(0..<n)
        size = Array(repeating: 1, count: n)
        count = n
    }

    mutating func find(_ x: Int) -> Int {
        if parent[x] != x {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    mutating func union(_ x: Int, _ y: Int) -> Bool {
        let rootX = find(x)
        let rootY = find(y)
        if rootX == rootY {
            return false
        }
        if size[rootX] < size[rootY] {
            parent[rootX] = rootY
            size[rootY] += size[rootX]
        } else {
            parent[rootY] = rootX
            size[rootX] += size[rootY]
        }
        count -= 1
        return true
    }
}

func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64) -> Int64 {
    let n = Int(n)
    let k = Int(k)
    var sortedEdges = edges.map { (edge: [Int64]) -> (Int, Int, Int64) in
        return (Int(edge[0]), Int(edge[1]), edge[2])
    }.sorted { $0.2 < $1.2 }

    var left: Int64 = 0
    var right: Int64 = sortedEdges.last?.2 ?? 0
    var answer: Int64 = right

    while left <= right {
        let mid = (left + right) / 2
        var uf = UnionFind(n)
        var components = n
        var maxCost: Int64 = 0

        for edge in sortedEdges {
            if edge.2 > mid {
                continue
            }
            if uf.union(edge.0, edge.1) {
                components -= 1
                maxCost = max(maxCost, edge.2)
            }
        }

        if components <= k {
            answer = mid
            right = mid - 1
        } else {
            left = mid + 1
        }
    }

    return answer
}
