func solve(n: Int64, edges: Array<Array<Int64>>, k: Int64): Int64 {
    let m = edges.length()
    if m == 0 {
        return 0
    }

    let sorted_edges = edges.copy()
    sorted_edges.sort_by(func(a: Array<Int64>, b: Array<Int64>): Bool {
        return a[2] < b[2]
    })

    let parent = Array<Int64>(n)
    let rank = Array<Int64>(n)
    for i in 0..n {
        parent[i] = i
        rank[i] = 0
    }

    func find(u: Int64): Int64 {
        if parent[u] != u {
            parent[u] = find(parent[u])
        }
        return parent[u]
    }

    var components = n
    var result: Int64 = 0

    for edge in sorted_edges {
        if components <= k {
            break
        }
        let u = edge[0]
        let v = edge[1]
        let w = edge[2]
        let root_u = find(u)
        let root_v = find(v)
        if root_u != root_v {
            if rank[root_u] > rank[root_v] {
                parent[root_v] = root_u
            } else if rank[root_u] < rank[root_v] {
                parent[root_u] = root_v
            } else {
                parent[root_v] = root_u
                rank[root_u] += 1
            }
            components -= 1
            result = max(result, w)
        }
    }

    return result
}
